INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a3a10900-0000-4000-8000-000000000000','a3a00000-0000-4000-8000-000000000000','確認テスト ─ 組織開発','quiz',NULL,NULL,NULL,3,2),
  ('a3a20900-0000-4000-8000-000000000000','a3a00000-0000-4000-8000-000000000000','確認テスト ─ 経営チームの組み立て','quiz',NULL,NULL,NULL,3,4),
  ('a3a30900-0000-4000-8000-000000000000','a3a00000-0000-4000-8000-000000000000','確認テスト ─ 後継者選定と承継','quiz',NULL,NULL,NULL,3,6),
  ('a3a40900-0000-4000-8000-000000000000','a3a00000-0000-4000-8000-000000000000','確認テスト ─ 組織文化の設計','quiz',NULL,NULL,NULL,3,8)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a3a10900-0000-4000-8000-000000000000','組織開発の本質として、本文が一行で示すのはどれか。','仕組みを変えると同時に人の関係性を変え、両者がたがいを支え合う状態を作ること','制度と構造を設計図通りに正しく組み立てること','人の意識を変えて自律的に動く集団を育てること','課題を人の問題か仕組みの問題かに切り分けて対処すること','A',0),
('a3a10900-0000-4000-8000-000000000000','本文が「罠」と呼ぶ、経営者の課題の捉え方はどれか。','出来事の背後にある構造まで遡って読もうとすること','課題を「人の問題か、仕組みの問題か」の二択で考えること','人と仕組みを噛み合わせて同時に動かそうとすること','レバレッジ・ポイントを一点に絞ろうとすること','B',1),
('a3a10900-0000-4000-8000-000000000000','ステップ3「仕組みと人を、セットで設計する」で、本文が示す注意点はどれか。','仕組みを入れてから人の手を後出しし、現場の反応を見て足す','仕組みの手と人の手は別々の担当に分けて並行で進める','人の手を、仕組みより先か同時に出し、言葉にしてはっきり渡す','まず全社一斉に導入し、噛み合いは後から調整する','C',2),
('a3a20900-0000-4000-8000-000000000000','経営チームの本質として、本文が一行で示すのはどれか。','優秀な部門長を数多く集め、作業を分担して回す集団','社長の考えを確認し、正しさを補強する賛成役の集団','一人では立てない判断を、たがいの視点と責任で支え合う三脚','社長が一番分かっている状態を保ちつつ意見を聞く場','C',0),
('a3a20900-0000-4000-8000-000000000000','本文で、経営チームの強さは何で決まるとされているか。','優秀な人を足し合わせた足し算','違う方向を向く強みが噛み合う掛け算','メンバー全員の勤続年数の長さ','社長への忠誠心の総量','B',1),
('a3a20900-0000-4000-8000-000000000000','ステップ4「判断を、実際に渡す」で、渡した判断が失敗したときの本文の注意点はどれか。','「だから言わんこっちゃない」と判断を取り上げる','結果が悪いときだけ判断を巻き取り、本人に反省させる','次からは会議で意見を聞くだけにとどめる','取り上げず、失敗も含めて共に引き受ける','D',2),
('a3a30900-0000-4000-8000-000000000000','承継の本質として、本文が一行で示すのはどれか。','ある日いきなり譲るのではなく、主役の座を降りる過程を年単位で設計すること','社長交代を発表し、肩書きを渡す引き継ぎの儀式','いちばん優秀な後継者を選び、一気に実権を渡すこと','自分がいる間、会社がうまく回る体制を保つこと','A',0),
('a3a30900-0000-4000-8000-000000000000','本文が、後継候補を見るときに挙げる四つの基準に含まれないのはどれか。','引き受ける姿勢','孤独に耐える力','いまの数字を出す速さ','人を生かす力','C',1),
('a3a30900-0000-4000-8000-000000000000','ステップ5「降りて、演出に回る」で、本文が最も戒める振る舞いはどれか。','後継が必要としたときの後ろ盾として残ること','降りると言いながら、結果が悪いときだけ口を出すこと','空いた時間を会社の外の活動に向けること','社内外に「これからはこの人が決める」と明確に示すこと','B',2),
('a3a40900-0000-4000-8000-000000000000','組織文化の本質として、本文が一行で示すのはどれか。','人が集まれば自然にできあがる空気','経営者が号令と掛け声で日々整えるもの','言葉と仕組みによって彫られた、人の判断の川床','理念を額に飾り、朝礼で語り継ぐ標語','C',0),
('a3a40900-0000-4000-8000-000000000000','本文で、文化を彫る二つの道具「言葉」と「仕組み」の役割はどれか。','言葉が方向を指し示し、仕組みがその方向へ人を流す','言葉が人を流し、仕組みが方向を指し示す','どちらも損得で人を動かす同じ役割を持つ','言葉だけで方向も推進力も生み出せる','A',1),
('a3a40900-0000-4000-8000-000000000000','失敗③「価値を、欲張って並べすぎる」への修正として、本文が示すのはどれか。','大事にしたい価値を十ほど挙げて網羅する','価値を三つまでに絞る','抽象的な美徳のまま掲げ続ける','価値ごとに担当役員を割り当てる','B',2);
